module mux_2to1 (
  input A,
  input B,
  input SEL,
  output Y
);

  wire NOT_SEL;
  wire AND1;
  wire AND2;
  wire OR;

  wire mux_output_inverter = ~SEL;
  assign NOT_SEL = mux_output_inverter;
  assign AND1 = A & NOT_SEL;
  assign AND2 = B & SEL;
  assign OR = AND1 | AND2;

  assign Y = OR;

endmodule
